package remote_logger

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/remote_logger"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type RemoteLogPublisherProxy struct {
	remote_logger.UnimplementedRemoteLogPublisherServer
	client remote_logger.RemoteLogPublisherClient
}

func init() {
	proxyutil.Register(&remote_logger.RemoteLogPublisher_ServiceDesc, NewRemoteLogPublisherProxy)
}
func NewRemoteLogPublisherProxy(cc grpc.ClientConnInterface) remote_logger.RemoteLogPublisherServer {
	return &RemoteLogPublisherProxy{client: remote_logger.NewRemoteLogPublisherClient(cc)}
}
func (p *RemoteLogPublisherProxy) Put(ctx context.Context, in *remote_logger.RemoteLogMessage) (*remote_logger.RemoteLogPutResponse, error) {
	return proxyutil.ProxyMethod[remote_logger.RemoteLogMessage, remote_logger.RemoteLogPutResponse](p.client.Put)(ctx, in)
}
func (p *RemoteLogPublisherProxy) PutAll(ctx context.Context, in *remote_logger.RemoteLogMessages) (*remote_logger.RemoteLogPutResponse, error) {
	return proxyutil.ProxyMethod[remote_logger.RemoteLogMessages, remote_logger.RemoteLogPutResponse](p.client.PutAll)(ctx, in)
}
